const input = $input.first().json;
const body = input.body ?? input;
const job = body.job ?? {};
const selectedIdea = (job.ideas ?? []).find((idea) => idea.id === body.selectedIdeaId) ?? (job.ideas ?? [])[0] ?? null;
const title = selectedIdea?.title ?? body.seedKeyword ?? 'Untitled topic';
const angle = selectedIdea?.angle ?? 'Research the topic from a practical SEO angle';
const relatedKeywords = selectedIdea?.relatedKeywords ?? [];

return [{
  json: {
    eventId: body.eventId,
    jobId: body.jobId,
    type: body.type ?? 'research',
    callbackUrl: body.callbackUrl,
    callbackSecret: body.callbackSecret,
    selectedIdeaId: body.selectedIdeaId,
    client: body.client,
    seedKeyword: body.seedKeyword,
    title,
    angle,
    relatedKeywords,
    research: {
      objective: `Build a Thai and Global research pack for "${title}" for client ${body.client ?? 'Unknown client'}.`,
      audience: `Readers searching for ${body.seedKeyword ?? title} who need practical guidance and trustworthy context.`,
      gaps: [
        'Many local articles summarize the topic but do not compare Thai and global guidance.',
        'Competitors often skip search-intent mapping and real audience pain points.',
        'Most articles miss FAQ coverage and internal-link opportunities for SEO clusters.'
      ],
      sources: [
        { region: 'TH', title: `${title} in Thai search context`, source: 'Thai search and community synthesis', insight: `Use the angle "${angle}" and connect it to common Thai wording and decision factors.` },
        { region: 'TH', title: `Keyword opportunities for ${body.seedKeyword ?? title}`, source: 'Keyword opportunity map', insight: `Related keywords: ${relatedKeywords.join(', ') || 'none supplied'}` },
        { region: 'Global', title: `${title} global best-practice baseline`, source: 'International reference synthesis', insight: 'Use global sources to strengthen factual framing, terminology, and reader trust.' },
        { region: 'Global', title: `${title} content gap opportunities`, source: 'SERP gap hypothesis', insight: 'Prioritize concise answers first, then practical detail, FAQs, and internal-link hooks.' }
      ]
    }
  }
}];
